import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useDispatch, useSelector } from 'react-redux';
import Drawer from '@material-ui/core/Drawer';
import List from '@material-ui/core/List';
import ListItem from '@material-ui/core/ListItem';
import ListItemText from '@material-ui/core/ListItemText';
import AddIcon from '@material-ui/icons/Add';
import DeleteIcon from '@material-ui/icons/Delete';
import IconButton from '@material-ui/core/IconButton';
import MenuIcon from '@material-ui/icons/Menu';
import { makeStyles } from '@material-ui/core/styles';
import { getPlayers } from '../../actions/players';

const useStyles = makeStyles((theme) => ({
  mainMenuContainer: {
    display: "flex",
    flexFlow: "column wrap",
    height: 300,
    overflow: "auto"
  },
  mainMenuItem: {
    fontSize: '1rem',
    paddingTop: 1,
    paddingBottom: 1,
  },
  subMenuItem: {
    fontSize: '0.2rem',
    paddingTop: 1,
    paddingBottom: 1,
    paddingLeft: theme.spacing(3),
  },
}));

const DrawerMenu = ({ categories, isAuthenticated }) => {
  const classes = useStyles();
  const [isDrawerOpen, setIsDrawerOpen] = useState(false);
  const [openSubMenus, setOpenSubMenus] = useState([]); // State för att hålla reda på öppna submenyer
  const dispatch = useDispatch();
  const history = useNavigate();
  const players = useSelector((state) => state.players.players);

  const handleDrawerOpen = () => {
    setIsDrawerOpen(true); // Öppna menyn
  };

  const handleDrawerClose = () => {
    setIsDrawerOpen(false); // Stäng menyn
  };

  const listPlayer = (e, mainMenu, sub) => {
    e.preventDefault();
    const categories = [mainMenu, sub];
    dispatch(getPlayers({ name: categories.join(',') }));
    history(`/players/search?searchQuery=${categories.join(',')}`, { redirect: true });
    // Stäng inte menyn efter att ett menyval har klickats på
  };

  const filterCategories = (categories) => {
    return categories.map(category => {
      const subMenusWithPlayers = category.subMenu.filter(subMenu => {
        return players.some(player => {
          const matchCategory = player.category.includes(category.mainMenu);
          const matchSubCategory = player.subCategory.includes(subMenu);
          return matchCategory && matchSubCategory;
        });
      });

      return { ...category, subMenu: subMenusWithPlayers };
    }).filter(category => category.subMenu.length > 0);
  };

  const renderCategories = isAuthenticated ? categories : filterCategories(categories);

  const handleSubMenuClick = (subMenu) => {
    if (openSubMenus.includes(subMenu)) {
      setOpenSubMenus(openSubMenus.filter(item => item !== subMenu)); // Stäng submenyn om den är öppen
    } else {
      setOpenSubMenus([...openSubMenus, subMenu]); // Öppna submenyn om den är stängd
    }
  };

  return (
    <div>
      <IconButton
        edge="start"
        color="inherit"
        aria-label="menu"
        onClick={handleDrawerOpen}
      >
        <MenuIcon />
      </IconButton>
      <Drawer anchor="top" open={isDrawerOpen} onClose={handleDrawerClose}>
        <div className={classes.mainMenuContainer}>
          {renderCategories.map((category) => {
            const { _id, mainMenu, subMenu } = category;

            if (!_id || !mainMenu || !subMenu) {
              return null;
            }

            return (
              <div key={_id}>
                <ListItem className={classes.mainMenuItem}>
                  <ListItemText primary={mainMenu} />
                  {isAuthenticated && (
                    <div>
                      <IconButton className={classes.iconButton}>
                        <AddIcon />
                      </IconButton>
                      <IconButton className={classes.iconButton}>
                        <DeleteIcon />
                      </IconButton>
                    </div>
                  )}
                </ListItem>
                <List component="div" disablePadding>
                  {subMenu.map((subItem, index) => {
                    const subItemId = subItem ? subItem._id : '';
                    const subItemText = subItem || '';

                    return (
                      <ListItem
                        key={`${subItemId}-${index}`}
                        button
                        onClick={(e) => {
                          listPlayer(e, mainMenu, subItem);
                        }}
                        className={classes.subMenuItem}
                      >
                        <ListItemText primary={subItemText} />
                        {isAuthenticated && (
                          <div>
                            <IconButton className={classes.iconButton} onClick={() => handleSubMenuClick(subItem)}>
                              {openSubMenus.includes(subItem) ? <DeleteIcon /> : <AddIcon />}
                            </IconButton>
                          </div>
                        )}
                      </ListItem>
                    );
                  })}
                </List>
              </div>
            );
          })}
        </div>
      </Drawer>
    </div>
  );
};

export default DrawerMenu;
